-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_cm2_pct_week AS
WITH base AS (
  SELECT
    brand_id,
    date_trunc('week', conversion_at) AS period,
    currency_code,
    channel,
    SUM(cm2_minor) AS cm2_minor,
    SUM(net_revenue_minor) AS net_revenue_minor
  FROM brain_serving.semantic_order
  WHERE conversion_at IS NOT NULL
    AND ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3, 4
)
SELECT
  brand_id,
  period,
  currency_code,
  channel,
  cm2_minor,
  net_revenue_minor,
  (CAST(cm2_minor AS double) / NULLIF(net_revenue_minor, 0)) AS cm2_pct
FROM base;
